There are some issues of `wl-clipboard-rs`.

## example code

copy.rs

```rust
use wl_clipboard_rs::copy::{MimeType, Options, Source};


fn main() {
    let mut opts = Options::new();
    opts.foreground(true);
    opts.copy(Source::Bytes("Hello world!".to_string().into_bytes().into()), MimeType::Autodetect).unwrap();
}

```

paste.rs
```rust
use std::io::Read;
use wl_clipboard_rs::{paste::{get_contents, ClipboardType, Error, MimeType, Seat}};

fn main() {
    let result = get_contents(ClipboardType::Regular, Seat::Unspecified, MimeType::Text);
    match result {
        Ok((mut pipe, _)) => {
            let mut contents = vec![];
            pipe.read_to_end(&mut contents).unwrap();
            println!("Pasted: {}", String::from_utf8_lossy(&contents));
        }

        Err(Error::NoSeats) | Err(Error::ClipboardEmpty) | Err(Error::NoMimeType) => {
            // The clipboard is empty or doesn't contain text, nothing to worry about.
        }

        Err(err) => Err(err).unwrap()
    }
}

```

